package FlickerCircuit {
    model FlickerCircuitModel {
        /* Assumptions: LED Vf ≈ 2.0 V, target LED current ≈ 10 mA. Timing uses standard NE555 astable formula f = 1.44/((Ra+2*Rb)*C). Mouser links provided as search queries to ensure sourceability. */
        block PowerSupply { property V : Real = 5.0; }
        block LED { property Vf : Real = 2.0; property If_target : Real = 0.01; property mouser_search : String = "https://www.mouser.com/Search/Refine?Keyword=LED+3mm+or+5mm"; }
        block Resistor { property R : Real; property mouser_search : String; }
        block Timer555 {
            property Ra : Real; property Rb : Real; property C : Real;
            property frequency : Real;
            property mouser_search : String = "https://www.mouser.com/Search/Refine?Keyword=NE555";
        }

        part V5 : PowerSupply;
        part led : LED;
        part r_led : Resistor { R = 330.0; mouser_search = "https://www.mouser.com/Search/Refine?Keyword=330+ohm+resistor"; } /* 330 Ω chosen (standard) for ~9.1 mA */
        part tmr : Timer555 { Ra = 20000.0; Rb = 62000.0; C = 1.0e-6; } /* Ra=20k, Rb=62k, C=1µF => f ≈ 10 Hz */

        constraint freqCalc inv tmr.frequency = 1.44 / ((tmr.Ra + 2.0 * tmr.Rb) * tmr.C);
        constraint freqSpec inv tmr.frequency >= 9.5 and tmr.frequency <= 10.5;

        constraint ledCurrentApprox inv ((V5.V - led.Vf) / r_led.R) >= 0.009 and ((V5.V - led.Vf) / r_led.R) <= 0.011; /* ensures ~10 mA with 330Ω */
    }
}
